#include<bits/stdc++.h>
using namespace std;
int t,n;
char w[55];//标准答案字符存储
string s[55];//标准答案转换后字符串存储
string A = "1000";
string B = "0100";
string C = "0010";
string D = "0001";
bool flg = true;
char c;
int id;
string qwq;
double markk,point;

void check(char g){
	cin >> qwq;
	if(flg == false) return;
	else {
		if((g == '1'&&qwq == "01")||(g == '0'&&qwq == "10")) printf("Type Correct\n");
		else printf("Type Incorrect\n");
	}
	return;
}
void pas(){
	markk = 100.00;
	for(int i = 1;i<=n;i++){
		cin >> qwq;
		if(qwq != s[i]) markk -= point;
	}
	if(flg == false)return;
	printf("%.1lf\n",markk);
}
int main(){
	std::ios::sync_with_stdio(false);
	cin >> t >> n;
	cin >> w;
	for(int i = 0;i<n;i++){
		if(w[i] == 'A') s[i+1] = A;
		else if(w[i] == 'B') s[i+1] = B;
		else if(w[i] == 'C') s[i+1] = C;
		else s[i+1] = D;
	}
	point = 100.00/n;
	for(int i = 1;i<=t;i++){
		flg = true;
		id = 0;
	for(int i = 1;i<=16;i++){
		cin >> c;
		if(c-'0' == 1) id += pow(2,16-i);
	}
	if(id >= 1&&id<=10000) printf("ID: %d\n",id);
	else {
		printf("Wrong ID\n");
		flg = false;
	}
		check(c);
		pas();
		printf("\n");
	}
	return 0;
}
